import sys

def check_password_strength():
    password = sys.stdin.readline().strip()

    has_digit = False
    has_upper = False
    has_special = False
    special_chars = "!@#$%"

    if len(password) < 8:
        print("Weak")
        return

    for char in password:
        if char.isdigit():
            has_digit = True
        elif char.isupper():
            has_upper = True
        elif char in special_chars:
            has_special = True

    if has_digit and has_upper and has_special:
        print("Strong")
    else:
        print("Weak")

check_password_strength()

